vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


    vec3 pos = vec3(vUv.x, vUv.y, q1);
    vec3 rc = texture3D(sampler_fw_noisevol_hq, pos);
    rc += texture3D(sampler_fw_noisevol_hq, 2*pos)*0.5;
    rc += texture3D(sampler_fw_noisevol_hq, 4*pos)*0.25;
    rc += texture3D(sampler_fw_noisevol_hq, 8*pos)*0.125;
    rc += texture3D(sampler_fw_noisevol_hq, 16*pos)*0.0625;
    //rc = rc*0.556;
    rc = (rc*rc*rc);
    rc -= GetBlur1(vUv);
    rc *= q3;

    vec2 ruv = vUv = 0.5 + (vUv-0.5)*(1-(rc.x*.05));
    ret = texture(sampler_fc_main, vec2(ruv.x, ruv.y)).xyz;

    vec3 noise2 = texture(sampler_noise_lq, vUvOriginal*uTexSize.xy*texsize_noise_lq.zw+rand_frame.xy);
    noise2 += mix(rc*2, 2, vRadius);

vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((vUv.xyy*q27
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q29
                     );
if(ret.x> q21*roam_cos.y && ret.x<= q24*roam_sin.x)ret.x += (noise9).x*1.5;
if(ret.y> q22*roam_sin.x && ret.y<= q25*roam_cos.x)ret.y -= (noise9).y*.5;
if(ret.z> q23*roam_cos.x && ret.z<= q26*roam_sin.y)ret.z *= (noise9).z*1.5;

    ret = ret+0.5*lum(cross((1-ret),(noise2)));

    ret *= 0.98;


  fragColor = ret;
}

